rules.pseudocode:
if E_aff < 0:
    S_star = S_eff * (1.0 + abs(E_aff))
else:
    S_star = S_eff

if S_star > Theta and adjacent_to_food:
    decision = 'eat'
elif S_star > Theta and not adjacent_to_food:
    decision = 'approach'
else:
    decision = 'restrain'

if S > 0:
    IC = clip(IC - delta_IC, 0.0, 1.0)
else:
    IC = clip(IC + rho_IC, 0.0, 1.0)

if ate_last_step:
    H = clip(H - phi_H, 0.0, 1.0)
else:
    H = clip(H + delta_H, 0.0, 1.0)

if ate_last_step:
    if last_food_palatability < 0.5:
        E_aff = clip(E_aff + 0.05, -1.0, 1.0)  # healthy choice feels good
    else:
        E_aff = clip(E_aff - 0.05, -1.0, 1.0)  # indulgent choice causes guilt
else:
    E_aff = clip(E_aff + 0.01 * random_sign(), -1.0, 1.0)  # small drift

n_visible = len([f for f in perception.resources.food if manhattan_dist(agent, f) <= 5])
if n_visible >= 2:
    WM = clip(WM + 0.1, 0.0, 1.0)
else:
    WM = clip(WM - 0.05, 0.0, 1.0)

current_food_config = str(sorted([(f.x, f.y) for f in perception.resources.food]))
context_changed = (current_food_config != prev_food_config) and (prev_food_config != '')
if context_changed:
    strategy_switched = (decision != prev_decision)
    if strategy_switched:
        CF = clip(CF + cf_improve_rate, 0.0, 1.0)
    else:
        CF = clip(CF - cf_degrade_rate, 0.0, 1.0)
prev_food_config = current_food_config
prev_decision = decision
